config.script:
$ErrorActionPreference = 'Stop'
$packageName    = '{{trigger.param.packageName}}'
$packageSource  = '{{trigger.param.packageSourcePath}}'
$manufacturer   = '{{trigger.param.packageManufacturer}}'
$packageVersion = '{{trigger.param.packageVersion}}'
$siteCode       = '{{trigger.param.sccmSiteCode}}'
$siteServer     = '{{trigger.param.sccmSiteServer}}'

Write-Output "=== SCCM: Create Package ==="
Write-Output "Name:   $packageName $packageVersion ($manufacturer)"
Write-Output "Source: $packageSource"
Write-Output "Site:   $siteCode on $siteServer"

try {
    $cmModule = if ($env:SMS_ADMIN_UI_PATH) { Join-Path $env:SMS_ADMIN_UI_PATH '..\ConfigurationManager.psd1' } else { $null }
    $sccmAvailable = $cmModule -and (Test-Path $cmModule)

    if ($sccmAvailable) {
        if (-not (Get-Module ConfigurationManager)) { Import-Module $cmModule }
        if (-not (Get-PSDrive -Name $siteCode -PSProvider CMSite -ErrorAction SilentlyContinue)) {
            New-PSDrive -Name $siteCode -PSProvider CMSite -Root $siteServer -Scope Global | Out-Null
        }
        Push-Location "$($siteCode):\"
        try {
            $created = New-CMPackage -Name $packageName -Manufacturer $manufacturer -Version $packageVersion -Path $packageSource
            $packageId = $created.PackageID
        } finally { Pop-Location }
        $mode = 'live'
    } else {
        # Simulation path - lets this workflow run on dev boxes without ConfigMgr installed.
        $packageId = 'SIM{0:D5}' -f (Get-Random -Maximum 99999)
        $mode = 'simulated'
        Write-Output '  [SIM] ConfigurationManager module not found - running simulation'
    }
    Write-Output "Package created: ID=$packageId (mode=$mode)"
} catch {
    Write-Error "SCCM package creation failed: $($_.Exception.Message)"
    throw
}

$ErrorActionPreference = 'Stop'
$packageId  = '{{pkg.param.packageId}}'
$siteCode   = '{{trigger.param.sccmSiteCode}}'
$siteServer = '{{trigger.param.sccmSiteServer}}'
$dpGroup    = '{{trigger.param.distributionPointGroup}}'

Write-Output "=== SCCM: Distribute Content ==="
Write-Output "PackageID: $packageId"
Write-Output "DP Group:  $dpGroup"

try {
    $cmModule = if ($env:SMS_ADMIN_UI_PATH) { Join-Path $env:SMS_ADMIN_UI_PATH '..\ConfigurationManager.psd1' } else { $null }
    $sccmAvailable = $cmModule -and (Test-Path $cmModule)
    $dpList = @()

    if ($sccmAvailable) {
        if (-not (Get-Module ConfigurationManager)) { Import-Module $cmModule }
        if (-not (Get-PSDrive -Name $siteCode -PSProvider CMSite -ErrorAction SilentlyContinue)) {
            New-PSDrive -Name $siteCode -PSProvider CMSite -Root $siteServer -Scope Global | Out-Null
        }
        Push-Location "$($siteCode):\"
        try {
            Start-CMContentDistribution -PackageId $packageId -DistributionPointGroupName $dpGroup
            $dpList = Get-CMDistributionPoint | Select-Object -ExpandProperty NetworkOSPath
        } finally { Pop-Location }
        $mode = 'live'
    } else {
        $dpList = @('\\DP01.corp.local','\\DP02.corp.local','\\DP03.corp.local')
        $mode = 'simulated'
        Write-Output '  [SIM] ConfigurationManager module not found - running simulation'
    }

    $dpCount   = $dpList.Count
    $dpSummary = $dpList -join ', '
    if ($dpCount -lt 1) { throw "No distribution points matched group '$dpGroup'" }
    Write-Output "Distributed to $dpCount DP(s): $dpSummary (mode=$mode)"
} catch {
    Write-Error "SCCM distribution failed: $($_.Exception.Message)"
    throw
}

$ErrorActionPreference = 'Stop'
$packageId  = '{{pkg.param.packageId}}'
$scopeName  = '{{trigger.param.securityScope}}'
$siteCode   = '{{trigger.param.sccmSiteCode}}'
$siteServer = '{{trigger.param.sccmSiteServer}}'

Write-Output "=== SCCM: Apply Security Scope ==="
Write-Output "PackageID: $packageId"
Write-Output "Scope:     $scopeName"

try {
    $cmModule = if ($env:SMS_ADMIN_UI_PATH) { Join-Path $env:SMS_ADMIN_UI_PATH '..\ConfigurationManager.psd1' } else { $null }
    $sccmAvailable = $cmModule -and (Test-Path $cmModule)

    if ($sccmAvailable) {
        if (-not (Get-Module ConfigurationManager)) { Import-Module $cmModule }
        if (-not (Get-PSDrive -Name $siteCode -PSProvider CMSite -ErrorAction SilentlyContinue)) {
            New-PSDrive -Name $siteCode -PSProvider CMSite -Root $siteServer -Scope Global | Out-Null
        }
        Push-Location "$($siteCode):\"
        try {
            $p = Get-CMPackage -Id $packageId
            if (-not $p) { throw "Package $packageId not found" }
            $s = Get-CMSecurityScope -Name $scopeName
            if (-not $s) { throw "Security scope '$scopeName' not found" }
            Add-CMObjectSecurityScope -InputObject $p -Scope $s
        } finally { Pop-Location }
        $mode = 'live'
    } else {
        $mode = 'simulated'
        Write-Output '  [SIM] ConfigurationManager module not found - running simulation'
    }

    $scopeApplied = $scopeName
    Write-Output "Security scope '$scopeApplied' applied to $packageId (mode=$mode)"
} catch {
    Write-Error "SCCM scope assignment failed: $($_.Exception.Message)"
    throw
}

$ErrorActionPreference = 'Stop'
$groupName = '{{trigger.param.adGroup1Name}}'
$ouPath    = '{{trigger.param.adOU}}'
$groupDesc = 'Parent security group for ProductX (provisioned by NodePilot)'

Write-Output "=== AD: Create Parent Group ==="
Write-Output "Group: $groupName"
Write-Output "OU:    $ouPath"

try {
    $adAvailable = $null -ne (Get-Module -ListAvailable -Name ActiveDirectory)

    if ($adAvailable) {
        Import-Module ActiveDirectory
        $existing = Get-ADGroup -Filter "Name -eq '$groupName'" -ErrorAction SilentlyContinue
        if ($existing) {
            $group1Dn  = $existing.DistinguishedName
            $group1Sid = $existing.SID.Value
            $action    = 'reused'
        } else {
            $g = New-ADGroup -Name $groupName -GroupScope Global -GroupCategory Security -Path $ouPath -Description $groupDesc -PassThru
            $group1Dn  = $g.DistinguishedName
            $group1Sid = $g.SID.Value
            $action    = 'created'
        }
        $mode = 'live'
    } else {
        $group1Dn  = "CN=$groupName,$ouPath"
        $group1Sid = 'S-1-5-21-SIM-' + (Get-Random -Maximum 99999)
        $action    = 'simulated'
        $mode      = 'simulated'
        Write-Output '  [SIM] ActiveDirectory module not found - running simulation'
    }

    Write-Output "Parent group $action: $group1Dn (mode=$mode)"
} catch {
    Write-Error "AD parent group provisioning failed: $($_.Exception.Message)"
    throw
}

$ErrorActionPreference = 'Stop'
$groupName = '{{trigger.param.adGroup2Name}}'
$ouPath    = '{{trigger.param.adOU}}'
$groupDesc = 'Child security group for ProductX users (provisioned by NodePilot)'

Write-Output "=== AD: Create Child Group ==="
Write-Output "Group: $groupName"
Write-Output "OU:    $ouPath"

try {
    $adAvailable = $null -ne (Get-Module -ListAvailable -Name ActiveDirectory)

    if ($adAvailable) {
        Import-Module ActiveDirectory
        $existing = Get-ADGroup -Filter "Name -eq '$groupName'" -ErrorAction SilentlyContinue
        if ($existing) {
            $group2Dn  = $existing.DistinguishedName
            $group2Sid = $existing.SID.Value
            $action    = 'reused'
        } else {
            $g = New-ADGroup -Name $groupName -GroupScope Global -GroupCategory Security -Path $ouPath -Description $groupDesc -PassThru
            $group2Dn  = $g.DistinguishedName
            $group2Sid = $g.SID.Value
            $action    = 'created'
        }
        $mode = 'live'
    } else {
        $group2Dn  = "CN=$groupName,$ouPath"
        $group2Sid = 'S-1-5-21-SIM-' + (Get-Random -Maximum 99999)
        $action    = 'simulated'
        $mode      = 'simulated'
        Write-Output '  [SIM] ActiveDirectory module not found - running simulation'
    }

    Write-Output "Child group $action: $group2Dn (mode=$mode)"
} catch {
    Write-Error "AD child group provisioning failed: $($_.Exception.Message)"
    throw
}

$ErrorActionPreference = 'Stop'
$parentName = '{{trigger.param.adGroup1Name}}'
$childName  = '{{trigger.param.adGroup2Name}}'
$parentDn   = '{{grp1.param.group1Dn}}'
$childDn    = '{{grp2.param.group2Dn}}'

Write-Output "=== AD: Nest Groups ==="
Write-Output "Parent: $parentName"
Write-Output "Child:  $childName"
Write-Output "Membership: $childDn -> $parentDn"

try {
    $adAvailable = $null -ne (Get-Module -ListAvailable -Name ActiveDirectory)

    if ($adAvailable) {
        Import-Module ActiveDirectory
        $alreadyMember = Get-ADGroupMember -Identity $parentDn -ErrorAction SilentlyContinue | Where-Object { $_.distinguishedName -eq $childDn }
        if ($alreadyMember) {
            $action = 'already-member'
        } else {
            Add-ADGroupMember -Identity $parentDn -Members $childDn
            $action = 'added'
        }
        $mode = 'live'
    } else {
        $action = 'simulated'
        $mode   = 'simulated'
        Write-Output '  [SIM] ActiveDirectory module not found - running simulation'
    }

    $nestMembership = "$childName -> $parentName"
    Write-Output "Nesting $action for $nestMembership (mode=$mode)"
} catch {
    Write-Error "AD group nesting failed: $($_.Exception.Message)"
    throw
}

